/* ===================================
   RESPONSIVE DESIGN - HireLoop
   Mobile-first responsive styles
   =================================== */

/* Mobile Menu Toggle */
.mobile-menu-toggle {
  display: none;
  background: transparent;
  border: 1px solid var(--border-light);
  border-radius: 8px;
  padding: 8px 12px;
  color: var(--text-primary);
  cursor: pointer;
  font-size: 20px;
  transition: all 0.2s;
  min-width: 44px;
  min-height: 44px;
}

.mobile-menu-toggle:hover {
  background: var(--bg-elevated);
  border-color: var(--accent-primary);
}

/* Mobile Navigation Overlay */
.nav-links.mobile-open {
  display: flex !important;
  flex-direction: column;
  position: fixed;
  top: 72px;
  left: 0;
  right: 0;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  padding: 24px;
  gap: 20px;
  z-index: 99;
  box-shadow: var(--shadow-lg);
  animation: slideDown 0.3s ease;
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Mobile dropdown adjustments */
.nav-links.mobile-open .nav-dropdown {
  width: 100%;
}

.nav-links.mobile-open .nav-dropdown-menu {
  position: static;
  opacity: 1;
  visibility: visible;
  transform: none;
  margin-top: 8px;
  display: none;
}

.nav-links.mobile-open .nav-dropdown.active .nav-dropdown-menu {
  display: block;
}

/* ===================================
   TABLET (768px - 1024px)
   =================================== */
@media (max-width: 1024px) {
  /* Hero adjustments */
  .hero {
    flex-direction: column;
    text-align: center;
    padding: 120px 24px 60px;
    gap: 48px;
  }

  .hero h1 {
    font-size: 52px;
  }

  .hero-subtitle {
    font-size: 18px;
  }

  .hero-cta {
    justify-content: center;
  }

  .hero-stats {
    justify-content: center;
  }

  .hero-visual {
    max-width: 400px;
  }

  /* Feature grid to 2 columns */
  .feature-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  /* Showcase grid adjustments */
  .showcase-grid {
    gap: 40px;
  }

  /* Dashboard grid adjustments */
  .dashboard-grid {
    grid-template-columns: 1fr;
    gap: 20px;
  }

  .omniscore-card {
    flex-direction: column;
    text-align: center;
  }

  .omniscore-factors-mini {
    grid-template-columns: 1fr;
  }

  .factor-mini:nth-child(odd) {
    border-right: none;
    padding-right: 0;
  }
}

/* ===================================
   MOBILE (< 768px)
   =================================== */
@media (max-width: 768px) {
  /* Show hamburger, hide desktop nav */
  .mobile-menu-toggle {
    display: block;
  }

  .nav-links {
    display: none;
  }

  .nav-auth {
    gap: 8px;
  }

  .nav-auth .btn {
    padding: 10px 16px;
    font-size: 14px;
  }

  /* Hero mobile */
  .hero {
    padding: 100px 20px 40px;
    gap: 40px;
  }

  .hero h1 {
    font-size: 36px;
    line-height: 1.2;
  }

  .hero-subtitle {
    font-size: 16px;
  }

  .hero-cta {
    flex-direction: column;
    gap: 12px;
    width: 100%;
  }

  .hero-cta .btn {
    width: 100%;
  }

  .hero-cta-dual {
    flex-direction: column;
    gap: 12px;
    width: 100%;
  }

  .hero-cta-dual .btn {
    width: 100%;
    min-width: auto;
  }

  .hero-stats {
    flex-direction: column;
    gap: 24px;
    text-align: center;
  }

  /* Section headers */
  .section-header h2 {
    font-size: 32px;
  }

  .section-header p {
    font-size: 16px;
  }

  /* Feature grid to single column */
  .feature-grid {
    grid-template-columns: 1fr;
  }

  .feature-card {
    padding: 24px;
  }

  /* Showcase grid mobile */
  .showcase-grid {
    grid-template-columns: 1fr;
    gap: 48px;
  }

  .showcase-feature {
    flex-direction: column;
    text-align: center;
  }

  .showcase-feature .feature-icon {
    font-size: 2rem;
  }

  /* Score badges mobile */
  .score-badges-grid {
    grid-template-columns: 1fr;
    gap: 24px;
  }

  .score-badge-card .score-value {
    font-size: 3rem;
  }

  /* Steps mobile */
  .steps {
    gap: 32px;
  }

  .step {
    flex-direction: column;
    gap: 16px;
  }

  .step-number {
    font-size: 36px;
  }

  .step-content h3 {
    font-size: 20px;
  }

  .step-content p {
    font-size: 15px;
  }

  /* Pricing cards mobile */
  .pricing-cards {
    grid-template-columns: 1fr;
    gap: 20px;
  }

  .pricing-card {
    padding: 32px 24px;
  }

  /* CTA mobile */
  .cta h2 {
    font-size: 32px;
  }

  .cta p {
    font-size: 16px;
  }

  /* Footer mobile */
  .footer-content {
    flex-direction: column;
    gap: 32px;
  }

  .footer-links {
    flex-direction: column;
    gap: 32px;
  }

  /* Dashboard mobile */
  .dashboard-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 16px;
  }

  .dashboard-actions {
    width: 100%;
    justify-content: flex-start;
  }

  .omniscore-card {
    flex-direction: column;
    gap: 24px;
    padding: 24px;
  }

  .omniscore-card .omniscore-circle {
    width: 100px;
