  /* Cards mobile */
  .card {
    padding: 20px;
  }

  .card-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
  }

  /* Tables mobile */
  .table-container {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
  }

  table {
    min-width: 600px;
  }

  /* Forms mobile */
  .form-row {
    flex-direction: column;
    gap: 16px;
  }

  .form-group {
    width: 100%;
  }

  /* Interview page mobile */
  .interview-container {
    flex-direction: column;
    gap: 20px;
  }

  .interview-sidebar {
    width: 100%;
    position: static;
  }

  .interview-main {
    margin-left: 0;
    padding: 20px;
  }

  /* Job board filters mobile */
  .filters-bar {
    flex-direction: column;
    gap: 12px;
  }

  .filter-group {
    width: 100%;
  }

  /* Job cards mobile */
  .job-card {
    padding: 20px;
  }

  .job-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
  }

  .job-meta {
    flex-wrap: wrap;
  }

  /* Auth pages mobile */
  .auth-container {
    padding: 20px;
  }

  .auth-card {
    padding: 32px 24px;
  }

  .auth-form {
    gap: 16px;
  }

  /* Modal mobile */
  .modal-content {
    width: 95%;
    max-width: 95%;
    margin: 20px auto;
    max-height: 90vh;
    overflow-y: auto;
  }

  /* Buttons mobile - ensure min tap target */
  .btn {
    min-height: 44px;
    padding: 12px 20px;
  }

  .btn-large {
    min-height: 48px;
    padding: 14px 24px;
  }

  /* Input fields - ensure min tap target */
  input,
  select,
  textarea,
  button {
    min-height: 44px;
  }

  textarea {
    min-height: 120px;
  }
}

/* ===================================
   SMALL MOBILE (< 480px)
   =================================== */
@media (max-width: 480px) {
  /* Extra small screens */
  .hero h1 {
    font-size: 28px;
  }

  .section-header h2 {
    font-size: 26px;
  }

  .nav-container {
    padding: 0 16px;
  }

  .hero,
  .features,
  .how-it-works,
  .pricing,
  .cta {
    padding-left: 16px;
    padding-right: 16px;
  }

  .omniscore-card {
    padding: 20px;
  }

  .feature-card {
    padding: 20px;
  }

  .pricing-card {
    padding: 24px 20px;
  }

  .score-badge-card {
    padding: 24px;
  }

  .score-badge-card .score-value {
    font-size: 2.5rem;
  }
}

/* ===================================
   TOUCH OPTIMIZATIONS
   =================================== */
@media (hover: none) and (pointer: coarse) {
  /* Touch device optimizations */
  .btn,
  .nav-links a,
  .nav-dropdown-toggle,
  a {
    min-height: 44px;
    min-width: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }

  /* Remove hover effects on touch devices */
  .feature-card:hover,
  .showcase-feature:hover {
    transform: none;
  }

  /* Larger tap targets for dropdowns */
  .nav-dropdown-toggle {
    padding: 12px 16px;
  }
}

/* ===================================
   LANDSCAPE MOBILE
   =================================== */
@media (max-width: 768px) and (orientation: landscape) {
  .hero {
    min-height: auto;
    padding-top: 80px;
    padding-bottom: 40px;
  }

  .hero h1 {
    font-size: 32px;
  }

  .modal-content {
    max-height: 80vh;
  }
}

/* ===================================
   UTILITY CLASSES
   =================================== */
.hide-mobile {
  display: block;
}

.show-mobile {
  display: none;
}

@media (max-width: 768px) {
  .hide-mobile {
    display: none !important;
  }

  .show-mobile {
    display: block !important;
  }
}

/* Responsive text sizes */
.text-responsive-xl {
  font-size: clamp(2rem, 5vw, 4rem);
}

.text-responsive-lg {
  font-size: clamp(1.5rem, 3vw, 2.5rem);
}

.text-responsive-md {
  font-size: clamp(1.125rem, 2vw, 1.5rem);
}

/* Responsive spacing */
.section-padding {
  padding: clamp(40px, 8vw, 100px) clamp(16px, 4vw, 24px);
}

